def fib(n: int) -> int:
    # Dictionary to store results of previous calculations
    memo = {0: 0, 1: 1}

    def helper(k: int) -> int:
        # Check if value is already in the dictionary
        if k in memo:
            return memo[k]

        # Recursive step with memoization
        memo[k] = helper(k - 1) + helper(k - 2)
        return memo[k]

    return helper(n)

